import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import aaImage from '../aa.jpg'; // Replace with your actual image path

const Login = () => {
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const res = await axios.post('http://localhost:5000/api/auth/login', {
        email,
        password,
      });
      localStorage.setItem('token', res.data.token);
      alert('Login successful!');
      navigate('/dashboard');
    } catch (err: any) {
      setError(err.response?.data?.message || 'Login failed!');
    }
  };

  return (
    <div
      style={{
        backgroundImage: `url(${aaImage})`,
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundRepeat: 'no-repeat',
        minHeight: '100vh',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
      }}
    >
      <div
        style={{
          backgroundColor: 'rgba(0, 0, 0, 0.8)',
          padding: '40px',
          borderRadius: '10px',
          width: '400px',
          color: 'white',
          textAlign: 'center',
        }}
      >
        <h2 style={{ marginBottom: '10px' }}>
          <span role="img" aria-label="clapper">
            🎬
          </span>{' '}
          Login to Movie App
        </h2>

        {error && <p style={{ color: 'red' }}>{error}</p>}

        <form onSubmit={handleLogin}>
          <label style={labelStyle}>Email</label>
          <input
            type="email"
            placeholder="fizza@example.com"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
            style={inputStyle}
          />

          <label style={labelStyle}>Password</label>
          <input
            type="password"
            placeholder="••••••••"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
            style={inputStyle}
          />

          <button type="submit" style={loginBtnStyle}>
            Login
          </button>

          <p style={{ color: '#ccc', marginTop: '15px' }}>
            Don’t have an account?{' '}
            <span
              onClick={() => navigate('/register')}
              style={{ color: 'red', cursor: 'pointer', textDecoration: 'underline' }}
            >
              Sign up
            </span>
          </p>
        </form>
      </div>
    </div>
  );
};

// 🎨 Styling
const inputStyle: React.CSSProperties = {
  width: '100%',
  padding: '12px',
  margin: '10px 0 20px',
  borderRadius: '6px',
  border: 'none',
  backgroundColor: '#333',
  color: '#fff',
  fontSize: '14px',
};

const loginBtnStyle: React.CSSProperties = {
  width: '100%',
  padding: '12px',
  backgroundColor: 'red',
  color: '#fff',
  fontWeight: 'bold',
  borderRadius: '6px',
  border: 'none',
  cursor: 'pointer',
  fontSize: '16px',
};

const labelStyle: React.CSSProperties = {
  textAlign: 'left',
  display: 'block',
  color: '#ccc',
  fontSize: '14px',
  marginBottom: '5px',
};

export default Login;
